        code: '<demo-page-layout testId="dashboard-page">\n  <demo-navigation-strip demoNavigation testId="dashboard-demo-navigation" [demo]="demo" />\n\n  <article demoIntro class="demo-card demo-card--stack" data-testid="dashboard-filters-card">\n    <div class="demo-card__header">\n      <div>\n        <p class="demo-eyebrow">Angular URL State</p>\n        <h2>Dashboard filters with browser history.</h2>\n      </div>\n\n      <div class="dashboard-actions">\n        <span class="demo-hint-pill" data-testid="dashboard-history-mode">History mode: push</span>\n      </div>\n    </div>\n\n    <p class="demo-card__summary">\n      Change the tab, toggle archived data, or apply a date preset. Then use the browser back and\n      forward buttons to move through the URL-backed dashboard history.\n    </p>\n\n    <div class="dashboard-tabs">\n      @for (tab of tabs; track tab) {\n        <button\n          type="button"\n          class="demo-tab-button"\n          [class.demo-tab-button--active]="state.tab() === tab"\n          [attr.data-testid]="\'dashboard-tab-\' + tab"\n          (click)="selectTab(tab)"\n        >\n          {{ tab }}\n        </button>\n      }\n    </div>\n\n    <div class="dashboard-filters-grid">\n      <label class="demo-field">\n        <span>Start date</span>\n        <input\n          type="date"\n          class="demo-input"\n          [ngModel]="startDateValue()"\n          (ngModelChange)="updateStartDate($event)"\n          data-testid="dashboard-start-date"\n        />\n      </label>\n\n      <label class="demo-field">\n        <span>End date</span>\n        <input\n          type="date"\n          class="demo-input"\n          [ngModel]="endDateValue()"\n          (ngModelChange)="updateEndDate($event)"\n          data-testid="dashboard-end-date"\n        />\n      </label>\n\n      <label class="dashboard-toggle">\n        <span>Include archived work</span>\n        <input\n          type="checkbox"\n          [ngModel]="state.showArchived()"\n          (ngModelChange)="toggleArchived($event)"\n          data-testid="dashboard-show-archived"\n        />\n      </label>\n    </div>\n\n    <div class="dashboard-preset-row">\n      <button\n        type="button"\n        class="demo-button demo-button--ghost"\n        data-testid="dashboard-preset-7-days"\n        (click)="applyPreset(7)"\n      >\n        Last 7 days\n      </button>\n      <button\n        type="button"\n        class="demo-button demo-button--ghost"\n        data-testid="dashboard-preset-30-days"\n        (click)="applyPreset(30)"\n      >\n        Last 30 days\n      </button>\n      <button\n        type="button"\n        class="demo-button demo-button--ghost"\n        data-testid="dashboard-clear-range"\n        (click)="clearRange()"\n      >\n        Clear range\n      </button>\n    </div>\n\n    <demo-status-strip\n      testId="dashboard-status-strip"\n      summaryTestId="dashboard-range-label"\n      urlTestId="dashboard-current-url"\n      [summary]="rangeLabel()"\n      [currentUrl]="currentUrl()"\n    />\n  </article>\n\n  <section demoPrimary class="dashboard-metric-grid" data-testid="dashboard-metric-grid">\n    @for (metric of metrics(); track metric.label) {\n      <article class="demo-card dashboard-metric-card" data-testid="dashboard-metric-card">\n        <p class="demo-eyebrow">{{ state.tab() }}</p>\n        <h3>{{ metric.value }}</h3>\n        <strong>{{ metric.label }}</strong>\n        <p>{{ metric.detail }}</p>\n      </article>\n    }\n  </section>\n\n  <demo-inspector-panel\n    demoAside\n    panelTestId="dashboard-inspector-panel"\n    snapshotTestId="dashboard-snapshot-json"\n    codeTestId="dashboard-code-sample"\n    title="Live state and source"\n    summary="Switch between the live dashboard state and the generated source excerpt that powers it."\n    [snapshotJson]="snapshotJson()"\n    [docsLinks]="demo.docsLinks"\n    [snippetId]="demo.codeSample.snippetId"\n  />\n</demo-page-layout>',
