        code: '<demo-page-layout testId="query-form-orders-page">\n  <demo-navigation-strip demoNavigation testId="query-form-orders-demo-navigation" [demo]="demo" />\n\n  <article\n    demoIntro\n    class="demo-card demo-card--stack"\n    data-testid="query-form-orders-controls-card"\n  >\n    <div class="demo-card__header">\n      <div>\n        <p class="demo-eyebrow">Angular Query Form</p>\n        <h2>Reactive Forms filters with shareable query state.</h2>\n      </div>\n\n      <div class="query-orders-actions">\n        <span class="demo-hint-pill" data-testid="query-form-orders-binding-mode"\n          >Manual apply + subset binding</span\n        >\n        <span class="demo-hint-pill" data-testid="query-form-orders-pending-state">{{\n          query.hasPendingChanges() ? \'Draft changes pending\' : \'URL is up to date\'\n        }}</span>\n        <button\n          type="button"\n          class="demo-button"\n          data-testid="query-form-orders-apply-filters"\n          [disabled]="!query.hasPendingChanges()"\n          (click)="applyFilters()"\n        >\n          Apply filters\n        </button>\n        <button\n          type="button"\n          class="demo-button demo-button--ghost"\n          data-testid="query-form-orders-discard-draft"\n          [disabled]="!query.hasPendingChanges()"\n          (click)="discardDraft()"\n        >\n          Discard draft\n        </button>\n        <button\n          type="button"\n          class="demo-button demo-button--ghost"\n          data-testid="query-form-orders-reset-filters"\n          (click)="resetFilters()"\n        >\n          Reset filters\n        </button>\n      </div>\n    </div>\n\n    <p class="demo-card__summary">\n      Search, status, and tag fields are the managed form subset. Their edits stage locally until\n      Apply, while page and page size stay directly URL-owned through the same query schema.\n    </p>\n\n    <form class="query-orders-controls-grid" [formGroup]="form">\n      <label class="demo-field">\n        <span>Search</span>\n        <input\n          type="search"\n          class="demo-input"\n          formControlName="search"\n          placeholder="Customer, region, or order ID"\n          data-testid="query-form-orders-search-input"\n        />\n      </label>\n\n      <label class="demo-field">\n        <span>Status</span>\n        <select\n          class="demo-select"\n          formControlName="status"\n          data-testid="query-form-orders-status-select"\n        >\n          @for (status of statusOptions; track status) {\n            <option [value]="status">{{ status }}</option>\n          }\n        </select>\n      </label>\n\n      <label class="demo-field">\n        <span>Page</span>\n        <input\n          #pageInput\n          type="number"\n          min="1"\n          class="demo-input"\n          [value]="currentPage()"\n          [disabled]="query.hasPendingChanges()"\n          data-testid="query-form-orders-page-input"\n          (input)="setPageFromInput(pageInput.value)"\n        />\n      </label>\n\n      <label class="demo-field">\n        <span>Page size</span>\n        <select\n          #pageSizeSelect\n          class="demo-select"\n          [disabled]="query.hasPendingChanges()"\n          data-testid="query-form-orders-page-size-select"\n          (change)="setPageSizeFromInput(pageSizeSelect.value)"\n        >\n          @for (size of pageSizeOptions; track size) {\n            <option [value]="size" [selected]="query.urlState.pageSize() === size">\n              {{ size }} rows\n            </option>\n          }\n        </select>\n      </label>\n\n      <fieldset class="query-orders-tag-fieldset" data-testid="query-form-orders-tags-fieldset">\n        <legend>Tags</legend>\n        <div class="query-orders-tag-row">\n          @for (tag of tagOptions; track tag) {\n            <button\n              type="button"\n              class="demo-tab-button"\n              [class.demo-tab-button--active]="form.controls.tags.value.includes(tag)"\n              [attr.data-testid]="\'query-form-orders-tag-\' + tag"\n              (click)="toggleTag(tag)"\n            >\n              {{ tag }}\n            </button>\n          }\n        </div>\n      </fieldset>\n    </form>\n\n    <p class="query-orders-mode-note" data-testid="query-form-orders-mode-note">\n      {{ stagingSummary() }} Apply or discard before changing pagination.\n    </p>\n\n    <demo-status-strip\n      testId="query-form-orders-status-strip"\n      summaryTestId="query-form-orders-result-summary"\n      urlTestId="query-form-orders-current-url"\n      [summary]="resultSummary()"\n      [currentUrl]="currentUrl()"\n    />\n  </article>\n\n  <article\n    demoPrimary\n    class="demo-card demo-card--stack"\n    data-testid="query-form-orders-table-card"\n  >\n    <div class="query-orders-table-head">\n      <div>\n        <p class="demo-eyebrow">Query-form snapshot</p>\n        <h3>Orders state</h3>\n      </div>\n      <div class="query-orders-pager">\n        <button\n          type="button"\n          class="demo-button demo-button--ghost"\n          data-testid="query-form-orders-previous-page"\n          [disabled]="query.hasPendingChanges()"\n          (click)="goToPage(currentPage() - 1)"\n        >\n          Previous\n        </button>\n        <span data-testid="query-form-orders-page-indicator"\n          >Page {{ currentPage() }} of {{ totalPages() }}</span\n        >\n        <button\n          type="button"\n          class="demo-button demo-button--ghost"\n          data-testid="query-form-orders-next-page"\n          [disabled]="query.hasPendingChanges()"\n          (click)="goToPage(currentPage() + 1)"\n        >\n          Next\n        </button>\n      </div>\n    </div>\n\n    <div class="query-orders-table-wrap" data-testid="query-form-orders-table-wrap">\n      <table class="query-orders-table" data-testid="query-form-orders-table">\n        <thead>\n          <tr>\n            <th>Order</th>\n            <th>Customer</th>\n            <th>Region</th>\n            <th>Age</th>\n            <th>Total</th>\n            <th>Tags</th>\n          </tr>\n        </thead>\n        <tbody>\n          @for (record of pagedOrders(); track record.id) {\n            <tr data-testid="query-form-orders-row">\n              <td>\n                <strong>{{ record.id }}</strong>\n                <span class="query-orders-status-chip">{{ record.status }}</span>\n              </td>\n              <td>{{ record.customer }}</td>\n              <td>{{ record.region }}</td>\n              <td>{{ record.ageDays }}d</td>\n              <td>{{ currency(record.total) }}</td>\n              <td>{{ record.tags.join(\', \') }}</td>\n            </tr>\n          } @empty {\n            <tr>\n              <td\n                colspan="6"\n                class="query-orders-empty-state"\n                data-testid="query-form-orders-empty-state"\n              >\n                No rows matched the current combination of query-form values.\n              </td>\n            </tr>\n          }\n        </tbody>\n      </table>\n    </div>\n  </article>\n\n  <demo-inspector-panel\n    demoAside\n    panelTestId="query-form-orders-inspector-panel"\n    snapshotTestId="query-form-orders-snapshot-json"\n    codeTestId="query-form-orders-code-sample"\n    title="Live state and source"\n    summary="Switch between the live query-form snapshot and the generated component excerpt that powers it."\n    [snapshotJson]="snapshotJson()"\n    [docsLinks]="demo.docsLinks"\n    [snippetId]="demo.codeSample.snippetId"\n  />\n</demo-page-layout>',
