        code: ':host {\n  display: block;\n}\n\n.query-orders-actions,\n.query-orders-pager,\n.query-orders-tag-row {\n  display: flex;\n  gap: 0.8rem;\n  align-items: center;\n  flex-wrap: wrap;\n}\n\n.query-orders-controls-grid {\n  display: grid;\n  gap: 1rem;\n  grid-template-columns: repeat(auto-fit, minmax(13rem, 1fr));\n}\n\n.query-orders-tag-fieldset {\n  display: grid;\n  gap: 0.75rem;\n  min-width: 0;\n  grid-column: 1 / -1;\n  margin: 0;\n  padding: 0;\n  border: 0;\n}\n\n.query-orders-tag-fieldset legend {\n  padding: 0;\n  margin-bottom: 0.2rem;\n  color: var(--color-ink);\n  font-size: 0.92rem;\n  font-weight: 600;\n}\n\n.query-orders-table-head {\n  display: flex;\n  gap: 1rem;\n  align-items: center;\n  justify-content: space-between;\n  flex-wrap: wrap;\n}\n\n.query-orders-table-wrap {\n  border: 1px solid var(--color-border);\n  border-radius: 1.15rem;\n  background: color-mix(in srgb, var(--color-surface-strong) 82%, white);\n  overflow-x: auto;\n}\n\n.query-orders-table {\n  width: 100%;\n  min-width: 46rem;\n  border-collapse: collapse;\n}\n\n.query-orders-table td:first-child {\n  white-space: nowrap;\n}\n\n.query-orders-table th,\n.query-orders-table td {\n  padding: 0.9rem 0.75rem;\n  text-align: left;\n  border-bottom: 1px solid var(--color-border);\n  color: var(--color-muted);\n}\n\n.query-orders-table th {\n  font-size: 0.86rem;\n  text-transform: uppercase;\n  letter-spacing: 0.08em;\n  color: var(--color-accent-strong);\n}\n\n.query-orders-status-chip {\n  display: inline-flex;\n  align-items: center;\n  margin-left: 0.65rem;\n  padding: 0.28rem 0.62rem;\n  border-radius: 999px;\n  background: linear-gradient(180deg, var(--color-accent-soft), rgba(217, 119, 75, 0.14));\n  color: var(--color-accent-strong);\n  font-size: 0.72rem;\n  text-transform: uppercase;\n  letter-spacing: 0.08em;\n}\n\n.query-orders-empty-state {\n  padding: 2rem 1rem;\n  border-radius: 1rem;\n  background: color-mix(in srgb, var(--color-surface-strong) 84%, white);\n  text-align: center;\n}\n\n.query-orders-mode-note {\n  margin: 0;\n  color: var(--color-muted);\n}\n\n@media (max-width: 720px) {\n  .query-orders-pager {\n    width: 100%;\n    justify-content: space-between;\n  }\n\n  .query-orders-table-wrap {\n    border-radius: 1rem;\n  }\n}',
