        sourcePath:
          'angular/apps/demo-angular/src/app/features/angular-async-state/pages/async-state-action-demo-page/async-state-action-demo-page.component.css',
        code: ':host {\n  display: block;\n}\n\n.async-toolbar {\n  display: flex;\n  gap: 0.8rem;\n  align-items: center;\n  flex-wrap: wrap;\n}\n\n.async-action-controls-grid {\n  display: grid;\n  gap: 1rem;\n  grid-template-columns: repeat(auto-fit, minmax(13rem, 1fr));\n}\n\n.async-action-controls-grid__select {\n  grid-column: span 2;\n}\n\n.async-action-grid {\n  display: grid;\n  gap: 1rem;\n  grid-template-columns: repeat(auto-fit, minmax(16rem, 1fr));\n}\n\n.async-order-card {\n  display: grid;\n  gap: 0.55rem;\n  padding: 1rem;\n  border: 1px solid var(--color-border);\n  border-radius: 1.1rem;\n  background: color-mix(in srgb, var(--color-surface-strong) 82%, white);\n  box-shadow: var(--shadow-soft);\n}\n\n.async-order-card strong {\n  font-size: 1.6rem;\n  line-height: 1;\n}\n\n.async-banner {\n  padding: 0.95rem 1rem;\n  border-radius: 1rem;\n  border: 1px solid var(--color-border);\n  box-shadow: var(--shadow-soft);\n}\n\n.async-banner--loading {\n  background: linear-gradient(180deg, rgba(225, 239, 250, 0.95), rgba(212, 230, 244, 0.78));\n}\n\n.async-banner--success {\n  background: linear-gradient(180deg, rgba(230, 247, 236, 0.94), rgba(217, 239, 224, 0.82));\n  border-color: rgba(46, 125, 50, 0.18);\n}\n\n.async-banner--error {\n  background: linear-gradient(180deg, rgba(255, 232, 232, 0.94), rgba(255, 214, 214, 0.8));\n  border-color: rgba(154, 31, 31, 0.18);\n}\n\n.async-banner--empty {\n  background: linear-gradient(180deg, rgba(244, 245, 247, 0.94), rgba(233, 236, 239, 0.8));\n}\n\n.async-fact-list {\n  display: grid;\n  gap: 0.5rem;\n  margin: 0;\n  padding-left: 1.1rem;\n  color: var(--color-muted);\n}\n\n@media (max-width: 720px) {\n  .async-action-controls-grid__select {\n    grid-column: span 1;\n  }\n}',
