        code: '.permissions-routing-toolbar {\n  display: grid;\n  gap: 1rem;\n  grid-template-columns: minmax(18rem, 24rem) minmax(0, 1fr);\n}\n\n.permissions-routing-toolbar__select {\n  min-width: 0;\n}\n\n.permissions-route-state {\n  display: flex;\n  align-items: center;\n  flex-wrap: wrap;\n  gap: 0.75rem;\n}\n\n.permissions-route-nav {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 0.75rem;\n}\n\n.permissions-route-nav__link {\n  border: 1px solid var(--demo-border, #d7dde4);\n  border-radius: 999px;\n  padding: 0.75rem 1.05rem;\n  text-decoration: none;\n  color: inherit;\n  background: color-mix(in srgb, var(--demo-surface, #ffffff) 96%, white);\n  box-shadow: var(--shadow-soft);\n}\n\n.permissions-route-nav__link--active {\n  background: linear-gradient(\n    180deg,\n    color-mix(in srgb, #d9edf7 72%, var(--demo-surface, #ffffff)),\n    color-mix(in srgb, #d7f0ec 56%, white)\n  );\n}\n\n.permissions-route-panel {\n  min-height: 14rem;\n}\n\n@media (max-width: 900px) {\n  .permissions-routing-toolbar {\n    grid-template-columns: 1fr;\n  }\n}',
